1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	}
5	
6	interface Step {
7	  type: string;
8	  items: Item[];
9	}
10	
11	interface Scenario {
12	  customer: { years: number };
13	  steps: Step[];
14	}
15	
16	interface Result {
17	  premium: number;
18	}
19	
20	interface ScenarioOutput {
21	  results: Result[];
22	}
23	
24	const PROCESSING_FEE = 5;
25	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
26	const BUILDING_BLOCK_PREMIUM = 60;
27	const BUILDING_BLOCK_SIZE = 3;
28	
29	const BASE_PREMIUMS: Record<string, number> = {
30	  sword: 100,
31	  amulet: 60,
32	  staff: 80,
33	  potion: 40,
34	  rune: 25,
35	};
36	
37	const groupItemsByType = (items: Item[]): Record<string, Item[]> => {
38	  const groups: Record<string, Item[]> = {};
39	  for (const item of items) {
40	    if (!groups[item.type]) {
41	      groups[item.type] = [];
42	    }
43	    groups[item.type].push(item);
44	  }
45	  return groups;
46	};
47	
48	const CURSED_SURCHARGE_RATE = 0.5;
49	
50	const calculateItemsPremium = (items: Item[]): number => {
51	  const itemsByType = groupItemsByType(items);
52	  let total = 0;
53	
54	  for (const [type, typeItems] of Object.entries(itemsByType)) {
55	    if (typeItems.length === BUILDING_BLOCK_SIZE) {
56	      total += BUILDING_BLOCK_PREMIUM;
57	    } else {
58	      for (const item of typeItems) {
59	        let itemPremium = BASE_PREMIUMS[type];
60	        if (item.cursed) {
61	          itemPremium += BASE_PREMIUMS[type] * CURSED_SURCHARGE_RATE;
62	        }
63	        total += itemPremium;
64	      }
65	    }
66	  }
67	
68	  return total;
69	};
70	
71	export function processScenario(scenario: Scenario): ScenarioOutput {
72	  const step = scenario.steps[0];
73	  const itemsPremium = calculateItemsPremium(step.items);
74	  const premium = itemsPremium + itemsPremium * FIRST_INSURANCE_SURCHARGE_RATE + PROCESSING_FEE;
75	  return { results: [{ premium }] };
76	}
